import java.util.*;

class Date {
    int day, month, year;

    Date(int day, int month, int year) {
        this.day = day;
        this.month = month;
        this.year = year;
    }
}

public class Main {

    // Method to compare two dates
    static boolean isEarlier(Date d1, Date d2) {
        if (d1.year != d2.year)
            return d1.year < d2.year;
        if (d1.month != d2.month)
            return d1.month < d2.month;
        return d1.day < d2.day;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);

        int n = sc.nextInt();
        Date[] dates = new Date[n];

        // Input dates
        for (int i = 0; i < n; i++) {
            int day = sc.nextInt();
            int month = sc.nextInt();
            int year = sc.nextInt();
            dates[i] = new Date(day, month, year);
        }

        // Selection Sort
        for (int i = 0; i < n - 1; i++) {
            int minIndex = i;

            for (int j = i + 1; j < n; j++) {
                if (isEarlier(dates[j], dates[minIndex])) {
                    minIndex = j;
                }
            }

            // Swap
            Date temp = dates[i];
            dates[i] = dates[minIndex];
            dates[minIndex] = temp;
        }

        // Output sorted dates
        for (Date d : dates) {
            System.out.println(d.day + " " + d.month + " " + d.year);
        }

        sc.close();
    }
}
